from langchain.agents import create_react_agent, AgentExecutor
from langchain.tools import tool

@tool
def get_weather(city: str) -> str:
    """Current weather for a city."""
    return {"Tokyo": "22C clear"}.get(city, "unknown")

agent = create_react_agent(llm, [get_weather], prompt)
executor = AgentExecutor(agent=agent, tools=[get_weather])
executor.invoke({"input": "Weather in Tokyo?"})

SAFE = {"search", "read_file", "calculator"}

def execute(call):
    if call.name not in SAFE:
        if not human_approves(call):   # confirm before acting
            return "Action denied by reviewer."
    return TOOLS[call.name](**call.args)
